// // (1) disable: Disables the counter. Active low.
// (2) sync_reset: Synchronous reset of the counter. Active low.
// (3) sync_load: Synchronous load of the counter. Active low.
// (4) sync_load_val: 8-bit value to load into the counter.
// (5) clk: Clock signal.
// (6) q: 8-bit output of the counter.
module top_module(
	input clk,
	input enable,
	input reset,
	input load,
	input [7:0] load_val,
	output reg [7:0] q);always @(posedge clk or posedge reset or posedge load) begin
	if (reset)
		q <= 8'b00000000;
	else if (load)
		q <= load_val;
	else if (enable)
		q <= q + 1;
end
endmodule

